    function updatePathCamera(){if(pathTracer){pathTracer.updateCamera();lastSamples=-1;el("sample-count").textContent="0 spp"}}controls.addEventListener("change",updatePathCamera);function resize(){const box=el("canvas").getBoundingClientRect();renderer.setSize(box.width,box.height,false);camera.aspect=box.width/Math.max(box.height,1);camera.updateProjectionMatrix();updatePathCamera()}new ResizeObserver(resize).observe(el("canvas"));resize();(function loop(){requestAnimationFrame(loop);controls.update();if(fields.highQuality.checked&&pathTracer){try{if(pathTracer.samples<96)pathTracer.renderSample();const samples=Math.floor(pathTracer.samples);if(samples!==lastSamples){lastSamples=samples;el("sample-count").textContent=samples+" spp";el("preview-state-copy").textContent=samples<96?"Rendering progressively — leave it running for a cleaner image":"Path trace complete"}}catch(error){disposePath();el("sample-count").textContent="Unavailable";el("preview-state-copy").textContent="Path tracing is unavailable";renderer.render(scene,camera)}}else renderer.render(scene,camera)})();el("focus").addEventListener("click",frameModel);
    let seq=0;const pending=new Map();function requestHost(method,params,timeout=30000){return new Promise((resolve,reject)=>{const id=++seq;pending.set(id,{resolve,reject});window.parent.postMessage({jsonrpc:"2.0",id,method,params},"*");setTimeout(()=>{if(pending.has(id)){pending.delete(id);reject(new Error("Host request timed out"))}},timeout)})}function callTool(name,args){return requestHost("tools/call",{name,arguments:args})}
    let displayMode=window.openai&&window.openai.displayMode==="fullscreen"?"fullscreen":"inline";function reportInlineHeight(){if(displayMode!=="inline")return;const height=560;if(window.openai&&window.openai.notifyIntrinsicHeight)window.openai.notifyIntrinsicHeight(height);window.parent.postMessage({jsonrpc:"2.0",method:"ui/notifications/size-changed",params:{width:Math.ceil(window.innerWidth),height}},"*")}function setDisplayMode(mode){displayMode=mode==="fullscreen"?"fullscreen":"inline";appShell.classList.toggle("is-fullscreen",displayMode==="fullscreen");fullscreenButton.setAttribute("aria-label",displayMode==="fullscreen"?"Exit fullscreen":"Open fullscreen");requestAnimationFrame(()=>{resize();reportInlineHeight()})}async function toggleFullscreen(){const target=displayMode==="fullscreen"?"inline":"fullscreen";try{let result;if(window.openai&&window.openai.requestDisplayMode)result=await window.openai.requestDisplayMode({mode:target});else result=await requestHost("ui/request-display-mode",{mode:target},4000);setDisplayMode(result&&result.mode||target)}catch(error){try{if(target==="fullscreen"&&document.documentElement.requestFullscreen)await document.documentElement.requestFullscreen();else if(target==="inline"&&document.fullscreenElement&&document.exitFullscreen)await document.exitFullscreen();setDisplayMode(target)}catch(fallbackError){}}}fullscreenButton.addEventListener("click",toggleFullscreen);document.addEventListener("fullscreenchange",()=>setDisplayMode(document.fullscreenElement?"fullscreen":"inline"));window.addEventListener("openai:set_globals",event=>{const mode=event.detail&&event.detail.globals&&event.detail.globals.displayMode;if(mode)setDisplayMode(mode)});setDisplayMode(displayMode);requestAnimationFrame(reportInlineHeight);
    function toolArgs(){const data=modelFromFields();return{text:data.text,font:data.font,text_case:data.textCase,font_weight:data.fontWeight,italic:data.italic,underline:data.underline,size_mm:data.sizeMm,depth_mm:data.depthMm,bevel_mm:data.bevelMm,bevel_segments:data.bevelSegments,curve_segments:data.curveSegments,bevel_side:data.bevelSide,smooth_normals:data.smoothNormals,material_preset:data.materialPreset,high_quality:data.highQuality}}
    window.addEventListener("message",event=>{if(event.source!==window.parent)return;const msg=event.data;if(!msg||msg.jsonrpc!=="2.0")return;if(msg.id&&pending.has(msg.id)){const p=pending.get(msg.id);pending.delete(msg.id);msg.error?p.reject(msg.error):p.resolve(msg.result);return}if(msg.method==="ui/notifications/tool-result"){const data=msg.params&&msg.params.structuredContent;if(data)renderModel(data,true)}if(msg.method==="ui/notifications/tool-input"){const data=msg.params&&msg.params.arguments;if(data)renderModel(data,true)}if(msg.method==="ui/notifications/host-context-changed"&&msg.params&&msg.params.displayMode)setDisplayMode(msg.params.displayMode)});
