    el("download").addEventListener("click",async()=>{const data=modelFromFields();const url=new URL("/api/stl",ORIGIN);url.search=new URLSearchParams({text:data.text,font:data.font,textCase:data.textCase,fontWeight:data.fontWeight,italic:String(data.italic),underline:String(data.underline),size:String(data.sizeMm),depth:String(data.depthMm),bevel:String(data.bevelMm),bevelSegments:String(data.bevelSegments),curveSegments:String(data.curveSegments),bevelSide:data.bevelSide,smoothNormals:String(data.smoothNormals)}).toString();const href=url.toString();if(window.openai&&window.openai.openExternal){await window.openai.openExternal({href})}else{window.open(href,"_blank","noopener,noreferrer")}});
    const initial=(window.openai&&window.openai.toolOutput)||(window.openai&&window.openai.toolInput)||{text:"Hello",font:"Roboto",fontId:"roboto",textCase:"original",fontWeight:"regular",italic:false,underline:false,sizeMm:36,depthMm:4,bevelMm:.6,bevelSegments:3,curveSegments:10,bevelSide:"both",smoothNormals:true,materialPreset:"pla-orange",highQuality:false};renderModel(initial,true);
